// 三载体一致:纯 JS,interpolate 返回 (t)=>path 字符串,无 DOM/shadow 足迹;interpolate 是命名导出
import { interpolate } from 'https://cdn.jsdelivr.net/npm/flubber@0.4.2/+esm';
const morph = interpolate(data.fromShape, data.toShape, { maxSegmentLength: data.maxSegmentLength ?? 10 });
// 消费 AI 自驱 t:0→1(rAF 或补间库),把 morph(t) 赋给 <path d> 或 canvas Path2D:
const d = morph(0.5);
